/**
 * Represents the response from the activator client.
 * @interface
 */
export interface ActivatorClientResponse {
    /**
     * The name of the service.
     * This should be composed by Fury's scope and the service name.
     * Example: `beta.events-flow-discovery`.
     */
    name: string;
    /**
     * The status of the service.
     * True if the service is active, otherwise false.
     */
    status: string;
    /**
     * The Fury's criticality of the service.
     */
    criticality: string;
}
